--
-- Table structure for table `recharge_stats`
--

DROP TABLE IF EXISTS `recharge_stats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `recharge_stats` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `cost_amount` decimal(18,2) DEFAULT '0.00',
  `customer_amount` decimal(18,2) DEFAULT '0.00',
  `customer_id` bigint NOT NULL,
  `customer_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `customer_price` decimal(19,2) NOT NULL,
  `product_id` bigint NOT NULL,
  `product_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `recharge_count` int DEFAULT '0',
  `stat_date` datetime(6) NOT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `supplier_id` bigint NOT NULL,
  `supplier_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `supplier_price` decimal(19,2) NOT NULL,
  `product_face_price` decimal(19,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_dimension_status` (`stat_date`,`product_id`,`customer_id`,`supplier_id`,`status`),
  KEY `idx_stat_date` (`stat_date`),
  KEY `idx_product` (`product_id`,`stat_date`),
  KEY `idx_customer` (`customer_id`,`stat_date`),
  KEY `idx_supplier` (`supplier_id`,`stat_date`),
  KEY `idx_status` (`status`,`stat_date`)
) ENGINE=InnoDB AUTO_INCREMENT=1197 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

